6	/**
7	 * Subscribes to the OIDC UserManager and exposes the signed-in user to the tree
8	 * (the generic-client replacement for msal-react's MsalProvider + useMsal). In
9	 * dev_bypass / unconfigured modes getUserManager() is null, so this is a
10	 * passthrough with a null user — CurrentUserProvider and AuthGate dispatch by
11	 * auth mode, so nothing reads the user in those modes.
12	 */
13	export function AuthProvider({ children }: { children: ReactNode }) {
14	  const mgr = getUserManager();
15	  const [user, setUser] = useState<User | null>(null);
16	
17	  useEffect(() => {
18	    if (!mgr) return;
19	    let active = true;
20	    // Seed from any persisted session, then track load/unload (sign-in, silent
21	    // renew, sign-out) so the tree re-renders on session changes.
22	    void mgr.getUser().then((u) => {
23	      if (active) setUser(u);
24	    });
25	    const onLoaded = (u: User) => setUser(u);
26	    const onCleared = () => setUser(null);
27	    mgr.events.addUserLoaded(onLoaded);
28	    mgr.events.addUserUnloaded(onCleared);
29	    // A failed background silent-renew or an IdP-side sign-out doesn't fire
30	    // userUnloaded — clear the user on those too, so the tree drops to the
31	    // sign-in page instead of showing a stale, half-broken authenticated UI.
32	    mgr.events.addSilentRenewError(onCleared);
33	    mgr.events.addUserSignedOut(onCleared);
34	    return () => {
35	      active = false;
36	      mgr.events.removeUserLoaded(onLoaded);
37	      mgr.events.removeUserUnloaded(onCleared);
38	      mgr.events.removeSilentRenewError(onCleared);
39	      mgr.events.removeUserSignedOut(onCleared);
40	    };
41	  }, [mgr]);
42	
43	  return <AuthContext.Provider value={{ user }}>{children}</AuthContext.Provider>;
44	}
