import { configDefaults, defineConfig } from 'vitest/config';
import react from '@vitejs/plugin-react';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';

const __dirname = dirname(fileURLToPath(import.meta.url));

// Proxy target for /api and /mcp. Defaults to localhost:8000 for host-side dev
// (`pnpm dev`); the docker-compose frontend service overrides it to the in-network
// api hostname (http://api:8000), since `localhost` inside the container is the
// frontend container itself.
const apiProxyTarget = process.env.VITE_API_PROXY_TARGET || 'http://localhost:8000';

export default defineConfig({
  plugins: [react()],
  resolve: {
    alias: {
      '@': resolve(__dirname, 'src'),
    },
  },
  server: {
    port: 3000,
    proxy: {
      '/api': apiProxyTarget,
      '/mcp': apiProxyTarget,
    },
  },
  build: {
    rollupOptions: {
      output: {
        // Split the heavy, rarely-changing vendors into their own long-cache
        // chunks so the app chunk stays small and an app change doesn't bust the
        // whole vendor bundle. Routes are additionally lazy-split (App.tsx).
        manualChunks(id: string) {
          if (!id.includes('node_modules')) return undefined;
          if (id.includes('/antd/') || id.includes('@ant-design/')) return 'antd';
          if (id.includes('@azure/')) return 'msal';
          // Monaco is huge (~4 MB) and only used by the custom-SQL editor — keep
          // it in its own chunk so the catch-all `vendor` doesn't pull it eagerly;
          // it's reached only via the React.lazy SqlEditorField (ADR 0019).
          if (id.includes('monaco-editor') || id.includes('@monaco-editor/')) return 'monaco';
          // recharts (+ its d3 deps) is only used by the dashboard chart widgets,
          // which live on lazy routes. Keep it out of the catch-all `vendor` chunk
          // (which loads eagerly) so it ships only when a chart route loads, like
          // monaco above (ADR 0022).
          if (
            id.includes('/recharts/') ||
            id.includes('/victory-vendor/') ||
            id.includes('/d3-') ||
            id.includes('/internmap/')
          ) {
            return 'recharts';
          }
          if (
            id.includes('/react/') ||
            id.includes('/react-dom/') ||
            id.includes('/react-router') ||
            id.includes('/scheduler/')
          ) {
            return 'react';
          }
          return 'vendor';
        },
      },
    },
  },
  test: {
    globals: true,
    environment: 'jsdom',
    setupFiles: ['./tests/setup.ts'],
    // Playwright specs live in e2e/ + e2e-live/ and run under `pnpm e2e`, not
    // Vitest — they import @playwright/test and drive a browser, so keep Vitest
    // out of them.
    exclude: [...configDefaults.exclude, 'e2e/**', 'e2e-live/**'],
    coverage: {
      provider: 'v8',
      reporter: ['text', 'lcov'],
      thresholds: {
        lines: 0, // raised to 80 in Week 8
      },
    },
  },
});

