  const improved = delta === 0 ? null : up === (goodWhen === 'up');
  const color = improved === null ? undefined : improved ? DELTA_GOOD : DELTA_BAD;
  return (
    <Typography.Text style={{ fontSize: 12, color }} type={improved === null ? 'secondary' : undefined}>
      {up ? <RiseOutlined /> : delta < 0 ? <FallOutlined /> : null}{' '}
      {`${up ? '+' : ''}${delta}${unit} vs prior period`}
    </Typography.Text>
  );
}

export function MetricCard({
  label,
  value,
  icon,
  unit,
  progress,
  delta,
  deltaUnit = '%',
  deltaGoodWhen = 'up',
  footnote,
  loading = false,
}: MetricCardProps) {
  return (
    <Card size="small" style={{ height: '100%' }}>
      <Flex vertical gap={12}>
        <Flex justify="space-between" align="flex-start" gap={8}>
          <Typography.Text type="secondary" style={{ fontSize: 13 }}>
            {label}
          </Typography.Text>
          <span
            aria-hidden
            style={{
              display: 'inline-flex',
              alignItems: 'center',
              justifyContent: 'center',
              width: 32,
              height: 32,
              borderRadius: 8,
              background: BRAND.selectedBg,
              color: BRAND.primary,
              flexShrink: 0,
            }}
          >
            {icon}
          </span>
        </Flex>

        {loading ? (
          <Skeleton.Input active size="large" style={{ width: 96 }} />
        ) : (
          <Flex align="baseline" gap={6}>
            <Typography.Title level={2} style={{ margin: 0, lineHeight: 1, color: BRAND.ink }}>
              {value === null ? '—' : value}
            </Typography.Title>
            {unit && value !== null && (
              <Typography.Text type="secondary" style={{ fontSize: 13 }}>
                {unit}
              </Typography.Text>
            )}
          </Flex>
        )}

        {progress != null && !loading && (
          <Progress percent={Math.round(progress)} showInfo={false} size="small" />
        )}
        {footnote && (
          <Typography.Text type="secondary" style={{ fontSize: 12 }}>
            {footnote}
          </Typography.Text>
        )}
      </Flex>
    </Card>
  );
}

