10	 * period-over-period delta, and an optional footnote — fronted by a tinted
11	 * icon chip.
12	 *
13	 * The delta (#352) is backed by a real prior-window aggregate from the summary
14	 * endpoint — `null`/omitted renders nothing rather than a fabricated 0 (KPI
15	 * honesty, ADR 0022 / 0018). `deltaGoodWhen` colours it by whether the
16	 * movement is an improvement ('down' for durations).
17	 *
18	 * `value === null` renders an em dash (no data for the window) rather than 0,
19	 * so an empty workspace reads as "nothing yet", not "scored zero".
20	 */
21	interface MetricCardProps {
22	  label: string;
23	  /** Pre-formatted display value, or `null` for the no-data em dash. */
24	  value: ReactNode | null;
25	  icon: ReactNode;
26	  /** Trailing unit shown next to the value (e.g. "%", "operational"). */
27	  unit?: string;
28	  /** 0–100 progress bar under the value; omit for plain count metrics. */
29	  progress?: number | null;
30	  /** Period-over-period delta; `null`/omitted → not rendered. */
31	  delta?: number | null;
32	  /** Suffix on the delta value (e.g. "%" for %-change, " pts" for points). */
33	  deltaUnit?: string;
34	  /** Which direction is an improvement (default 'up'; 'down' for durations). */
35	  deltaGoodWhen?: 'up' | 'down';
36	  footnote?: string;
37	  loading?: boolean;
38	}
39	
40	const DELTA_GOOD = '#3f8600';
41	const DELTA_BAD = '#cf1322';
42	
43	function DeltaBadge({
44	  delta,
45	  unit,
46	  goodWhen,
47	}: {
48	  delta: number;
49	  unit: string;
50	  goodWhen: 'up' | 'down';
51	}) {
52	  const up = delta > 0;
53	  const improved = delta === 0 ? null : up === (goodWhen === 'up');
54	  const color = improved === null ? undefined : improved ? DELTA_GOOD : DELTA_BAD;
55	  return (
56	    <Typography.Text
57	      style={{ fontSize: 12, color }}
58	      type={improved === null ? 'secondary' : undefined}
59	    >
60	      {up ? <RiseOutlined /> : delta < 0 ? <FallOutlined /> : null}{' '}
61	      {`${up ? '+' : ''}${delta}${unit} vs prior period`}
62	    </Typography.Text>
63	  );
64	}
65	
66	export function MetricCard({
67	  label,
68	  value,
69	  icon,
70	  unit,
71	  progress,
72	  delta,
73	  deltaUnit = '%',
74	  deltaGoodWhen = 'up',
75	  footnote,
76	  loading = false,
77	}: MetricCardProps) {
78	  return (
79	    <Card size="small" style={{ height: '100%' }}>
80	      <Flex vertical gap={12}>
81	        <Flex justify="space-between" align="flex-start" gap={8}>
82	          <Typography.Text type="secondary" style={{ fontSize: 13 }}>
83	            {label}
84	          </Typography.Text>
85	          <span
86	            aria-hidden
87	            style={{
88	              display: 'inline-flex',
89	              alignItems: 'center',
90	              justifyContent: 'center',
91	              width: 32,
92	              height: 32,
93	              borderRadius: 8,
94	              background: BRAND.selectedBg,
95	              color: BRAND.primary,
96	              flexShrink: 0,
97	            }}
98	          >
99	            {icon}
100	          </span>
101	        </Flex>
102	
103	        {loading ? (
104	          <Skeleton.Input active size="large" style={{ width: 96 }} />
105	        ) : (
106	          <Flex align="baseline" gap={6}>
107	            <Typography.Title level={2} style={{ margin: 0, lineHeight: 1, color: BRAND.ink }}>
108	              {value === null ? '—' : value}
109	            </Typography.Title>
110	            {unit && value !== null && (
111	              <Typography.Text type="secondary" style={{ fontSize: 13 }}>
112	                {unit}
113	              </Typography.Text>
114	            )}
115	          </Flex>
116	        )}
117	
118	        {progress != null && !loading && (
119	          <Progress percent={Math.round(progress)} showInfo={false} size="small" />
120	        )}
121	        {delta != null && !loading && value !== null && (
122	          <DeltaBadge delta={delta} unit={deltaUnit} goodWhen={deltaGoodWhen} />
123	        )}
124	        {footnote && (
125	          <Typography.Text type="secondary" style={{ fontSize: 12 }}>
126	            {footnote}
127	          </Typography.Text>
128	        )}
129	      </Flex>
130	    </Card>
131	  );
132	}

